mapper.select:
select t.id as task_id, t.name as task_name, coalesce(t.transfer_name, t.transfer_type, '') as transfer_name, greatest(t.uts, t.cts) as stats_time, t.status, t.total_count as list_total, coalesce(t.dialed_count, 0) as dialed_count, coalesce(t.answered_count, 0) as answered_count, concat( round( case when coalesce(t.dialed_count, 0) > 0 then coalesce(t.answered_count, 0) * 100.0 / t.dialed_count else 0 end, 1 ), '%' ) as answer_rate, 0 as pending_count, coalesce((select count(distinct l.agent_id) from cc_agent_state_log l where l.state = 'OUT_CALL' and l.company_id = t.company_id), 0) as in_call, 0 as queue_count, coalesce((select count(distinct l.agent_id) from cc_agent_state_log l where l.state != 'LOGOUT' and l.company_id = t.company_id), 0) as signed_in_agents, coalesce((select count(distinct l.agent_id) from cc_agent_state_log l where l.state = 'READY' and l.company_id = t.company_id), 0) as idle_agents, coalesce((select count(distinct l.agent_id) from cc_agent_state_log l where l.state = 'NOT_READY' and l.company_id = t.company_id), 0) as busy_agents, 0 as after_call_agents, 0 as abandoned_count from cc_task_config t
t.company_id = #{companyId} and t.id = #{taskId} and t.status = #{status}
order by t.id desc
